const https = require('https');
const token = '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';
const store = '7089d1-4e.myshopify.com';

const query = JSON.stringify({
  query: \`{
    orders(first: 250, query: \"created_at:>=2026-04-01 AND created_at:<=2026-04-12\") {
      edges {
        node {
          id
          name
          createdAt
          totalPriceSet { shopMoney { amount } }
          lineItems(first: 10) {
            edges {
              node {
                title
                quantity
              }
            }
          }
        }
      }
    }
  }\`
});

const options = {
  hostname: store,
  path: '/admin/api/2024-01/graphql.json',
  method: 'POST',
  headers: {
    'X-Shopify-Access-Token': token,
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(query)
  }
};

const req = https.request(options, (res) => {
  let data = '';
  res.on('data', (chunk) => data += chunk);
  res.on('end', () => {
    try {
      const parsed = JSON.parse(data);
      const orders = parsed.data.orders.edges;

      let totalRevenue = 0;
      let orderCount = 0;
      let productSales = {};
      let dailySales = {};
      let giftCount = 0;

      orders.forEach(({node: o}) => {
        orderCount++;
        const revenue = parseFloat(o.totalPriceSet.shopMoney.amount);
        totalRevenue += revenue;

        const date = o.createdAt.slice(5, 10); // MM-DD
        dailySales[date] = (dailySales[date] || {count: 0, rev: 0});
        dailySales[date].count++;
        dailySales[date].rev += revenue;

        let hasGift = false;
        o.lineItems.edges.forEach(({node: item}) => {
          const title = item.title;
          const qty = item.quantity;

          if (title.includes('桐箱') || title.includes('紙袋')) {
            hasGift = true;
          } else {
            productSales[title] = productSales[title] || {qty: 0, orders: 0};
            productSales[title].qty += qty;
            productSales[title].orders++;
          }
        });
        if (hasGift) giftCount++;
      });

      console.log('=== 4/1-4/12 Shopify注文サマリー ===');
      console.log('総注文数:', orderCount);
      console.log('総売上:', totalRevenue);
      console.log('AOV:', Math.round(totalRevenue / orderCount));
      console.log('ギフト系付帯:', giftCount, '件 /', orderCount, '件');
      console.log('');
      console.log('=== 日別売上 ===');
      Object.keys(dailySales).sort().forEach(d => {
        console.log(d + ':', dailySales[d].count + '件', '¥' + Math.round(dailySales[d].rev));
      });
      console.log('');
      console.log('=== 商品別 ===');
      Object.entries(productSales).sort((a,b) => b[1].qty - a[1].qty).forEach(([title, data]) => {
        console.log(title.slice(0,50) + ':', data.qty + '個', data.orders + '件');
      });

    } catch(e) {
      console.log('Error:', e.message, data.slice(0,300));
    }
  });
});
req.on('error', (e) => console.log('Error:', e.message));
req.write(query);
req.end();
